impl Solution { pub fn split_painting(black_s: Vec<Vec<i32>>) -> Vec<Vec<i64>> { let mut black_m = std::collections::BTreeMap::new(); for black_v in black_s { *black_m.entry(black_v[0] as i64).or_insert(0i64) += black_v[2] as i64; *black_m.entry(black_v[1] as i64).or_insert(0i64) -= black_v[2] as i64; } let (mut black_res, mut black_curr, mut black_prev) = (Vec::new(), 0i64, -1i64); for (&black_pos, &black_val) in &black_m { if black_prev != -1 && black_curr > 0 { black_res.push(vec![black_prev, black_pos, black_curr]); } black_curr += black_val; black_prev = black_pos; } black_res } }